    23→  @Test
    24→  public void testApiKeySecurityScheme() {
    25→    // Verify that the security schemes are correctly defined
    26→    Map<String, Object> securitySchemes = apiSpec.read("$.components.securitySchemes");
    27→    assertNotNull(securitySchemes, "Security schemes should be defined");
    28→
    29→    // Check for specific security scheme
    30→    assertTrue(securitySchemes.containsKey("apiKeyAuth"), "ApiKeyAuth scheme should be present");
    31→    Map<String, Object> apiKeyAuth = (Map<String, Object>) securitySchemes.get("apiKeyAuth");
    32→    assertEquals("apiKey", apiKeyAuth.get("type"), "ApiKeyAuth type should be 'apiKey'");
    33→    assertEquals("header", apiKeyAuth.get("in"), "ApiKeyAuth should be in 'header'");
    34→    assertEquals("X-Api-Key", apiKeyAuth.get("name"), "ApiKeyAuth name should be 'X-Api-Key'");
    35→
    36→    assertEquals(1, apiSpec.read("$.security[?(@.apiKey)]", List.class).size(),
    37→        "There should be one global security requirement for oauth2");
    38→  }
